export function initialize(sentinelElement, dotNetHelper) {
    const observer = new IntersectionObserver(entries => {
        if (entries[0].isIntersecting) {
            dotNetHelper.invokeMethodAsync('OnSentinelVisible');
        }
    }, { rootMargin: '128px' });

    observer.observe(sentinelElement);

    return observer;
}

export function dispose(observer) {
    observer.disconnect();
}

@typeparam TItem
@implements IAsyncDisposable

<div class="infinite-scroll-container">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="sentinelRef" class="infinite-scroll-sentinel">
            @if (isLoading)
            {
                <div class="infinite-scroll-spinner" role="status">
                    <span class="visually-hidden">Loading…</span>
                </div>
            }
        </div>
    }
</div>

using Microsoft.AspNetCore.Components;
using Microsoft.JSInterop;

namespace sv_2ec71bc10d2f4372873ab29dca9d1706.Components;

public partial class InfiniteScrollList<TItem> : IAsyncDisposable
{
    [Inject] private IJSRuntime JS { get; set; } = default!;

    [Parameter, EditorRequired] public IReadOnlyList<TItem> Items { get; set; } = [];
    [Parameter, EditorRequired] public bool HasMore { get; set; }
    [Parameter, EditorRequired] public EventCallback OnLoadMore { get; set; }
    [Parameter, EditorRequired] public RenderFragment<TItem> ChildContent { get; set; } = default!;

    private ElementReference sentinelRef;
    private IJSObjectReference? module;
    private IJSObjectReference? observer;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? dotNetRef;
    private bool isLoading;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            dotNetRef = DotNetObjectReference.Create(this);
            module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./js/infinite-scroll.js");
            observer = await module.InvokeAsync<IJSObjectReference>(
                "initialize", sentinelRef, dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (isLoading || !HasMore)
            return;

        isLoading = true;
        StateHasChanged();

        await OnLoadMore.InvokeAsync();

        isLoading = false;
        StateHasChanged();
    }

    public async ValueTask DisposeAsync()
    {
        if (observer is not null && module is not null)
        {
            await module.InvokeVoidAsync("dispose", observer);
            await module.DisposeAsync();
        }
        dotNetRef?.Dispose();
    }
}

.infinite-scroll-container {
    overflow-y: auto;
}

.infinite-scroll-sentinel {
    display: flex;
    justify-content: center;
    padding: 1rem 0;
    min-height: 1px;
}

.infinite-scroll-spinner {
    width: 2rem;
    height: 2rem;
    border: 0.25rem solid currentColor;
    border-right-color: transparent;
    border-radius: 50%;
    animation: infinite-scroll-spin 0.75s linear infinite;
}

@keyframes infinite-scroll-spin {
    to { transform: rotate(360deg); }
}

